var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그 아저씨들 정말 너무해요. 사람을 이렇게 만신창이로 만들다니.","JPN":"あのおじさんたち、ひどすぎます。一般人をこんなにボロボロにするなんて。","ENG":"What a bunch of jerks. How can they beat a man to a pulp like its nothing?","TWN":"那些大叔太過分了。竟然把人打成這樣。"},"stage":{"bg":"WARZONE_01","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"사람이 아니라 빚쟁이라 그렇지. 빌려 준 돈 받아내기는 쉽지 않아.","JPN":"一般人じゃなくて債務者だ。貸したお金はそう簡単に戻ってこないぞ。","ENG":"Because he's not a man but a debtor. It's not so easy getting these fools to pay back.","TWN":"因為他是欠債人。收回欠款可不是容易的事。"},"stage":{"bg":"WARZONE_01","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"전 매달 성실하게 갚고 있는걸요!","JPN":"私は毎月真面目に返済していますよ！","ENG":"But I've been paying back diligently every month!","TWN":"我每個月都有認真還債！"},"stage":{"bg":"WARZONE_01","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너처럼 성실하게 갚는 사람들은 애초에 우리들이랑 엮일 일도 없어.","JPN":"お前みたいに真面目に返済する奴は、そもそも最初から私たちと取引することはない。","ENG":"Diligent people don't end up getting involved with us in the first place.","TWN":"像你這樣認真還債的人，根本不可能跟我們攪合在一起。"},"stage":{"bg":"WARZONE_01","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저기 소파에 눕혀 놔. 곧 의식이 돌아올 거야.","JPN":"そこのソファに寝かせておけ。そのうち意識が戻ってくるだろう。","ENG":"Lay him down on that couch over there. He should wake up soon enough.","TWN":"把他放在那邊的沙發上，應該馬上就會醒來了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"금방 오겠다더니 저녁식사에 지각했군요. 역시 휴먼들의 약속은 믿을 게 못 됩니다.","JPN":"すぐ戻ると言って夕飯に遅刻しましたね。やはりヒューマンの約束を信じてはいけません。","ENG":"You said you'd be back soon, but you're late for dinner. I knew I couldn't count on a human's promise.","TWN":"說好馬上回來的，都過了晚餐時間了。真不能相信人類所謂的約定。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다녀왔습니다, 대표님!","JPN":"ただいまです、代表！","ENG":"We're back, boss!","TWN":"我們回來了，BOSS！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"밥도 안 먹는 기계 주제에 저녁 식사는 무슨.","JPN":"ふん、飯も食べない機械のくせに夕飯とはね。","ENG":"You're a machine. Why you got to give us a hassle over dinner?","TWN":"你是個機器又不用吃飯，介意晚餐做什麼。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이가 설치는 바람에 일이 좀 꼬였어.","JPN":"ガキがやらかしたせいでちょっと仕事がこじれた。","ENG":"Things got a bit complicated thanks to the kid.","TWN":"都怪這個小鬼，把事情弄得亂七八糟的。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"샤워 하고 올 동안 녀석이 맞는지 확인해 봐. 엄한 놈 성형시키고 내뺐을지도 모르니까.","JPN":"シャワーを浴びてくるから本当に本人なのか確認しておいてくれ。赤の他人を整形させてしらばっくれてる可能性もあるから。","ENG":"Check him and make sure he's our guy while I go wash up. Who knows if they gave some other bum a facelift just to throw us off.","TWN":"我先去洗澡，你檢查一下那個傢伙，也有可能是找人整形成自己的樣子後，本人已經跑路了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"보자 보자 하니까 이젠 대표한테 일을 떠넘기는 겁니까. 진공관 맙소사.","JPN":"代表に仕事をなすりつけるのですか？　オーマイ、真空管。","ENG":"Now you're making your employer perform your duties? Oh my diodes.","TWN":"我是不是對你太好了啊，竟敢指使你老闆做事？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 리타 언니! 저도 같이 들어갈래요! 물 절약해야죠!","JPN":"あっ、リタお姉ちゃん！　私も一緒に入ります！　水道代を節約しないと！","ENG":"Oh, Rita! Let me jump in the shower with you! We ought to conserve water!","TWN":"啊，麗塔姐姐！我也要一起洗！要節約用水嘛！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"들어오면 죽여 버린다.","JPN":"入ってきたら殺す。","ENG":"Do that and it's your funeral.","TWN":"你進來我就宰了你。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"지문 감식 결과가 나왔습니다.","JPN":"指紋照会結果が出ました。","ENG":"The fingerprint results are here.","TWN":"指紋鑒別結果出來了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"계약서에 찍은 지장과 대조한 결과, 몇 개월 전 잠적했던 윌버 본인이 확실합니다.","JPN":"契約書の指印と照らし合わせた結果、数ヶ月前から行方をくらましていたウィルバー本人で間違いありません。","ENG":"This man's prints match the one on the contract. He must be that Wilbur who went off the grid months ago.","TWN":"跟合約上的指紋對比結果顯示，確實是幾個月前失蹤的韋爾伯本人。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"우리 사무소에 몇 명 없는 장기 채무자를 찾아내다니, 대시는 이 일에 소질이 있군요.","JPN":"うちの会社でも数少ない長期債務者を見つけるとは、ダッシュはこの仕事の素質があると思います。","ENG":"You've managed to find one of the few long-term debtors to our company. You have a knack for this, Dash.","TWN":"竟然找到了我們事務所消失的長期債務人之一，黛西很有天賦嘛。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};